#include<bits/stdc++.h>
using namespace std;
#define int long long
//Ten years of OI for nothing, withoutlong long, I'll see my ancestors
//十年OI一场空，不开long long见祖宗 
signed main() {
    int T;
    cin >> T;
    while (T --) {
        int n;
        int ans0 = 0, ans1 = 0;
        string s, t;
        cin >> n >> s;
        s = " " + s;
        t = s;
        if (t[1] == '1') {
            t[1] = '0';
            ans0 = 1;
        }
        for (int i = n, j = 1;;) {
            while (t[i] == '0' && j < i)i--;
            if (i <= j)break;
            t[i] = '0';
            ans0 = ans0 + i - j + 1;
            j++;
            if (i <= j)break;
            if (t[j] == '1') {
                ans0++;
                t[j] = '0';
            }
        }
        if (s[1] == '0') {
            s[1] = '1';
            ans1 = 1;
        }
        for (int i = n, j = 1;;) {
            while (s[i] == '1' && j < i)i--;
            if (i <= j)break;
            ans1 = ans1 + i - j + 1;
            s[i] = '1';
            j++;
            if (i <= j)break;
            if (s[j] == '0') {
                ans1++;
                s[j] = '1';
            }
        }
        cout << min(ans0, ans1) << endl;
    }
    return 0;
}
